def remove_Occ(s: str, char: str) -> str:
    """
    Remove the first and last occurrence of a given character from the string.

    Parameters:
        s (str): Input string.
        char (str): Character to remove (must be a single character).

    Returns:
        str: New string with the first and last occurrences of the character removed.

    Raises:
        ValueError: If the character is not a single character or not found.
    """
    if len(char) != 1:
        raise ValueError("char must be a single character.")

    if char not in s:
        raise ValueError(f"Character '{char}' not found in string.")

    first_occurrence = s.find(char)
    last_occurrence = s.rfind(char)

    if first_occurrence == last_occurrence:
        # Only one occurrence; removing it once
        return s[:first_occurrence] + s[first_occurrence+1:]

    # Remove both first and last occurrences
    if first_occurrence == 0:
        if last_occurrence == len(s) - 1:
            return s[1:-1]
        else:
            return s[first_occurrence+1:last_occurrence]
    elif last_occurrence == len(s) - 1:
        return s[:first_occurrence] + s[last_occurrence:]
    else:
        return s[:first_occurrence] + s[first_occurrence+1:last_occurrence] + s[last_occurrence+1:]

