def text_lowercase_underscore(s: str) -> bool:
    if not s:
        return False

    # Check if the string contains only lowercase letters and underscores
    if not all(c.islower() or c == '_' for c in s):
        return False

    # Check that underscores are only used as separators between lowercase letters
    # and not at the start, end, or consecutively
    if s.startswith('_') or s.endswith('_'):
        return False

    if '__' in s:
        return False

    # Ensure that underscores are only between lowercase letters
