def is_undulating(n: int) -> bool:
    """
    Check if the given number is undulating.
    An undulating number is a number that alternates between increasing and decreasing.
    For example: 1212121 (1<2>1<2>1<2>1) is undulating.
    Single digit numbers are not considered undulating.
    """
    s = str(n)
    if len(s) < 3:
        return False

    increasing = False
    for i in range(1, len(s)):
        if s[i] > s[i-1]:
            if increasing:
                return False
            increasing = True
        elif s[i] < s[i-1]:
            if not increasing:
                return False
            increasing = not increasing
        else:
            return False  # Equal adjacent digits not allowed

    return True

