def search(arr):
    """
    Find the element that appears only once in a sorted array.

    Args:
        arr (List[int]): A sorted list of integers where exactly one element appears once.

    Returns:
        int: The unique element.
    """
    n = len(arr)
    if n == 0:
        raise ValueError("Array must contain at least one element.")

    # Check if the first element is unique
    if arr[0] != arr[1]:
        return arr[0]

    # Check if the last element is unique
    if arr[-1] != arr[-2]:
        return arr[-1]

    # Binary search for the unique element
    left, right = 0, n - 1
    while left < right:
        mid = (left + right) // 2

        # If mid is even, compare with next element
        if mid % 2 == 0:
            if arr[mid] == arr[mid + 1]:
                left = mid + 2
            else:
                right = mid
        else:
            # If mid is odd, compare with previous element
            if arr[mid] == arr[mid - 1]:
                right = mid - 2
            else:
                left = mid + 2

    return arr[left]

