def amicable_numbers_sum(n):
    def sum_divisors(num):
        if num <= 1:
            return 0
        total = 1  # 1 is always a divisor for num > 1
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                total += i
                if i != num // i:
                    total += num // i
        return total

    amicable_pairs = set()
    for num in range(2, n + 1):
        d_sum = sum_divisors(num)
        if d_sum != num and d_sum <= n:
            if sum_divisors(d_sum) == num:
                pair = (min(num, d_sum), max(num, d_sum))
                if pair not in amicable_pairs:
                    amicable_pairs.add(pair)

    return sum(num for pair in amicable_pairs for num in pair)

