    Check if a number is a Woodall number.
    A Woodall number is defined as n * 2^n - 1 for some positive integer n.
    """
    if n <= 0:
        return False

    # Check if n can be represented as k * 2^k - 1 for some positive integer k
    k = 1
    while True:
        woodall_num = k * (2 ** k) - 1
        if woodall_num == n:
            return True
        if woodall_num > n:
            return False
        k += 1

