def bell_number(n):
    if n < 0:
        return 0
    if n == 0:
        return 1

    # Compute Bell number using Stirling numbers of the second kind
    # B(n) = sum_{k=0}^{n} S(n,k)

    # Initialize Stirling numbers table
    S = [[0] * (n + 1) for _ in range(n + 1)]

    # S(0,0) = 1
    S[0][0] = 1

    # Fill in Stirling numbers
    for i in range(1, n + 1):
        for j in range(1, i + 1):
            S[i][j] = j * S[i - 1][j] + S[i - 1][j - 1]

    # Sum all S(n,k) for k from 0 to n
    return sum(S[n][k] for k in range(n + 1))

def is_Monotonic(arr):
    if len(arr) <= 1:
        return True

    # Check if non-decreasing or non-increasing
    is_non_decreasing = True
    is_non_increasing = True

    for i in range(len(arr) - 1):
        if arr[i] > arr[i + 1]:
            is_non_decreasing = False
        if arr[i] < arr[i + 1]:
            is_non_increasing = False

    return is_non_decreasing or is_non_increasing

