    if n == 1:
        return 1

    a = [0] * (n + 1)
    a[1] = 1

    for i in range(2, n + 1):
        if i % 2 == 1:
            a[i] = a[a[i - 1]]
        else:
            a[i] = a[a[i - 1]] + a[i - a[i - 1]]

    return a[n]

