def search(arr):
    """
    Find the element that appears only once in a sorted array.
    Uses binary search for O(log n) time complexity.
    """
    n = len(arr)

    if n == 0:
        return None

    # Check if the last element is unique (appears only once)
    if arr[-1] != arr[-2]:
        return arr[-1]

    # Binary search to find the unique element
    left, right = 0, n - 1

    while left < right:
        mid = (left + right) // 2

        # If mid is even, check if arr[mid] should equal arr[mid+1]
        if mid % 2 == 0:
            if arr[mid] == arr[mid + 1]:
                left = mid + 1
            else:
                right = mid
        else:
            # If mid is odd, check if arr[mid] should equal arr[mid-1]
            if arr[mid] == arr[mid - 1]:
                right = mid - 1
            else:
                left = mid

    return arr[left]

