        mid = left + (right - left) // 2

        # If mid is at an even index, compare with mid + 1
        if mid % 2 == 0:
            if arr[mid] == arr[mid + 1]:
                # Pair exists, unique element is to the right
                left = mid + 2
            else:
                # Pair doesn't exist, unique element is at mid or to the left
                right = mid
        else:
            # If mid is at an odd index, compare with mid - 1
            if arr[mid] == arr[mid - 1]:
                # Pair exists, unique element is to the right
                left = mid + 1
            else:
                # Pair doesn't exist, unique element is at mid or to the left
                right = mid

    return arr[left]

