def bell_number(n):
    if n < 0:
        return 0
    if n == 0:
        return 1

    # Bell triangle method
    bell_triangle = [[1]]
    for i in range(1, n + 1):
        row = [bell_triangle[i-1][j] + bell_triangle[i-1][j-1] if j > 0 else bell_triangle[i-1][0] for j in range(i)]
