    digits = [int(d) for d in s]

    # Check alternating pattern
    for i in range(len(digits) - 1):
        if i == 0:
            # First comparison must be increasing
            if digits[i] >= digits[i + 1]:
                return False
        else:
            # Must alternate direction
            if (digits[i] > digits[i + 1]) == (digits[i - 1] > digits[i]):
                return False

    return True

