def eulerian_num(n, m):
    if m < 0 or m >= n:
        return 0
    if n == 0:
        return 1 if m == 0 else 0

    # dp[i][j] represents A(i, j)
    dp = [[0] * (m + 1) for _ in range(n + 1)]
    dp[0][0] = 1

    for i in range(1, n + 1):
        for j in range(0, i):
            dp[i][j] = (i - 1) * dp[i - 1][j] + i * dp[i - 1][j - 1]

    return dp[n][m]

