def odd_Equivalent(s, n):
    length = len(s)
    if length == 0:
        return 0

    # Calculate effective rotations (mod length)
    n = n % length

    if n == 0:
        # No rotation needed, count odd values in original string
        return sum(1 for i in range(length) if int(s[i]) == 1)

    # Count odd values in rotated string
    count = 0
    for i in range(length):
        # Character at position i in rotated string is at position (i + n) % length in original
        if int(s[(i + n) % length]) == 1:
            count += 1

    return count

