def magic_square_test(matrix):
    n = len(matrix)

    if n == 0 or len(matrix[0]) != n:
        return False

    # Check if all elements are distinct and within 1 to n^2
    flat_matrix = [num for row in matrix for num in row]
    if len(set(flat_matrix)) != n * n:
        return False

    # Check if all elements are between 1 and n^2
    if any(num < 1 or num > n * n for num in flat_matrix):
        return False

    # Calculate the magic constant (sum of each row, column, and diagonal)
    magic_sum = sum(matrix[0])

    # Check all rows
    for row in matrix:
        if sum(row) != magic_sum:
            return False

    # Check all columns
    for col_idx in range(n):
        col_sum = sum(matrix[row_idx][col_idx] for row_idx in range(n))
        if col_sum != magic_sum:
            return False

    # Check main diagonal
    main_diag_sum = sum(matrix[i][i] for i in range(n))
    if main_diag_sum != magic_sum:
        return False

    # Check anti-diagonal
    anti_diag_sum = sum(matrix[i][n - 1 - i] for i in range(n))
    if anti_diag_sum != magic_sum:
        return False

    return True

def magic_square_test(matrix):
    """
    Check if a matrix is a magic square.
    A magic square is an n x n grid containing numbers from 1 to n^2,
    where each row, column, and both diagonals sum to the same value.
    """
    n = len(matrix)
    if n == 0:
        return False

    # Check if all numbers are from 1 to n^2
    numbers = set()
    for row in matrix:
        for num in row:
            if num < 1 or num > n * n or num in numbers:
                return False
            numbers.add(num)

    if len(numbers) != n * n:
        return False

    # Calculate the expected sum (each row/col/diag should sum to this)
    expected_sum = n * (n * n + 1) // 2

    # Check all rows
    for row in matrix:
        if sum(row) != expected_sum:
