    # Memoization to store computed values
    memo = {1: 1}

    def compute(k):
        if k in memo:
            return memo[k]

        # Apply the Newman-Conway sequence rule
        if k % 2 == 1:  # odd
            result = compute(compute(k - 1))
        else:  # even
            result = k - compute(k - 1)

        memo[k] = result
        return result

