def sequence(n):
    """
    Find the nth number in the Newman-Conway sequence.

    The Newman-Conway sequence is defined recursively:
    - a(1) = 1
    - a(n) = a(n-1) + a(n - a(n-1)) for n > 1

    This is a memoized recursive implementation.
    """
    memo = {}

    def helper(k):
        if k in memo:
            return memo[k]

        if k == 1:
            memo[k] = 1
        else:
            memo[k] = helper(k - 1) + helper(k - helper(k - 1))

        return memo[k]

    return helper(n)

