def eulerian_num(n, m):
    if m < 0 or m > n:
        return 0
    if n == 0:
        return 1 if m == 0 else 0

    # Create a 2D array for dynamic programming
    dp = [[0] * (n + 1) for _ in range(n + 1)]

    # Base case: A(n, 0) = 1 for all n
    for i in range(n + 1):
        dp[i][0] = 1

    # Fill the table using the recurrence relation
    for i in range(2, n + 1):
        for j in range(1, i):
            dp[i][j] = (j + 1) * dp[i-1][j] + (i - j) * dp[i-1][j-1]

    return dp[n][m]

def odd_Equivalent(s, n):
    count = 0
    for i in range(n):
        rotated = s[i:] + s[:i]
        ones = rotated.count('1')
        if ones % 2 == 1:
            count += 1
    return count

def odd_Equivalent(s, n):
    if len(s) == 0:
        return 0

    count = 0
    for i in range(n):
        # Rotate left by one position
        rotated = s[1:] + s[0]
        # Check if the last bit is '1' (odd number)
        if rotated[-1] == '1':
            count += 1

    return count

