def search(arr):
    """
    Find the element that appears only once in a sorted array.
    Uses binary search for O(log n) time complexity.
    """
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # Check if mid is the unique element
        if mid == 0:
            # First element - check if it's unique
            if arr[mid] != arr[mid + 1]:
                return arr[mid]
            else:
                left = mid + 1
        elif mid == len(arr) - 1:
            # Last element - check if it's unique
            if arr[mid] != arr[mid - 1]:
                return arr[mid]
            else:
                right = mid - 1
        else:
            # Middle element - check if it's unique
            if arr[mid] != arr[mid - 1] and arr[mid] != arr[mid + 1]:
                return arr[mid]
            elif arr[mid] == arr[mid - 1]:
                # Unique element is to the right
                left = mid + 1
            else:
                # Unique element is to the left
                right = mid - 1

    return arr[left]

