def amicable_numbers_sum(n):
    def sum_proper_divisors(num):
        if num <= 1:
            return 0
        total = 1  # 1 is always a proper divisor
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                total += i
                if i != num // i:
                    total += num // i
        return total

    amicable_sum = 0
    seen = set()

    for i in range(1, n + 1):
        d1 = sum_proper_divisors(i)

        # Check if i and d1 form an amicable pair
        if d1 != i and d1 <= n:
            d2 = sum_proper_divisors(d1)
            if d2 == i:
                # Both numbers are amicable and within range
                if i not in seen and d1 not in seen:
                    amicable_sum += i + d1
                    seen.add(i)
                    seen.add(d1)

    return amicable_sum

