def is_woodall(n):
    """
    Check if the given number is a Woodall number.
    A Woodall number is a number of the form W(n) = 2^n - n.
    """
    if n < 0:
        return False

    i = 1
    while True:
        woodall = (2 ** i) - i
        if woodall == n:
            return True
        if woodall > n:
            return False
        i += 1

